import sys
from functools import lru_cache
from math import comb

MOD = 998244353

def main():
    input_data = sys.stdin.read().split()
    n, x = int(input_data[0]), int(input_data[1])

    @lru_cache(maxsize=None)
    def solve(n, x):
        if n == 1:
            return 0

        result = 0
        b = 1
        while True:
            lo = (b-1)*(n-1) + 1
            if lo > x:
                break
            s = b*(n-1)
            hi_die = min(s, x)
            die_count = hi_die - lo + 1
            survive_count = max(0, x - s)

            for k in range(0, n):
                if k == 1:
                    continue
                dying = n - k
                if dying < 1:
                    continue
                if k > 0 and survive_count == 0:
                    continue

                if k == 0:
                    no_winner_k = 1
                else:
                    no_winner_k = solve(k, x - s)

                ways = comb(n, k) * pow(die_count, dying, MOD) % MOD * no_winner_k % MOD
                result = (result + ways) % MOD

            b += 1

        return result

    print(solve(n, x))

